import React, { useEffect, useState } from 'react';
import { studentsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';
import toast from 'react-hot-toast';
import { useNotifications } from '../../context/NotificationContext';
import { Search, Plus, Edit, Trash2, Eye, Key, Filter, Users, GraduationCap, Loader2 } from 'lucide-react';

const ManageStudents = () => {
  const { addNotification } = useNotifications();
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState({ yearLevel: '', section: '', status: '' });
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState(null);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState({
    studentId: '', password: '', firstName: '', middleName: '', lastName: '',
    gender: '', email: '', contactNumber: '', address: '',
    yearLevel: '', section: '', statusRecord: 'Regular',
    guardianName: '', guardianContact: '', skills: []
  });

  useEffect(() => {
    fetchStudents();
  }, [filters]);

  const fetchStudents = async () => {
    setLoading(true);
    try {
      const response = await studentsAPI.getAll({ ...filters, search: searchTerm });
      if (response.data.success) {
        setStudents(response.data.students);
      }
    } catch (error) {
      console.error('Error fetching students:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchStudents();
  };

  const handleAddStudent = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await studentsAPI.create(formData);
      toast.success('Student added successfully');
      addNotification({
        type: 'system',
        title: 'New Student Added',
        message: `${formData.firstName} ${formData.lastName} has been added to the system`,
        icon: 'Users',
        color: 'green',
        actionUrl: '/admin/students'
      });
      setShowAddModal(false);
      resetForm();
      fetchStudents();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to add student');
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateStudent = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await studentsAPI.update(selectedStudent.id, formData);
      toast.success('Student updated successfully');
      setShowEditModal(false);
      fetchStudents();
    } catch (error) {
      toast.error('Failed to update student');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteStudent = async (id) => {
    if (!window.confirm('Are you sure you want to delete this student?')) return;
    try {
      await studentsAPI.delete(id);
      toast.success('Student deleted');
      fetchStudents();
    } catch (error) {
      toast.error('Failed to delete student');
    }
  };

  const handleResetPassword = async (id) => {
    const newPassword = prompt('Enter new password (min 6 characters):');
    if (!newPassword || newPassword.length < 6) return;
    try {
      await studentsAPI.resetPassword(id, newPassword);
      toast.success('Password reset successfully');
    } catch (error) {
      toast.error('Failed to reset password');
    }
  };

  const resetForm = () => {
    setFormData({
      studentId: '', password: '', firstName: '', middleName: '', lastName: '',
      gender: '', email: '', contactNumber: '', address: '',
      yearLevel: '', section: '', statusRecord: 'Regular',
      guardianName: '', guardianContact: '', skills: []
    });
  };

  const openEditModal = (student) => {
    setSelectedStudent(student);
    setFormData({
      firstName: student.first_name || '',
      middleName: student.middle_name || '',
      lastName: student.last_name || '',
      gender: student.gender || '',
      email: student.email || '',
      contactNumber: student.contact_number || '',
      address: student.address || '',
      yearLevel: student.year_level || '',
      section: student.section || '',
      statusRecord: student.status_record || 'Regular',
      guardianName: student.guardian_name || '',
      guardianContact: student.guardian_contact || '',
      skills: student.skills?.map(s => s.name) || []
    });
    setShowEditModal(true);
  };

  const openViewModal = (student) => {
    setSelectedStudent(student);
    setShowViewModal(true);
  };

  const skillOptions = ['Programming', 'Networking', 'Database', 'UI/UX', 'Cybersecurity', 'Basketball', 'Volleyball', 'Esports', 'Chess'];

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 via-blue-700 to-blue-800 rounded-2xl p-6 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="relative z-10 flex items-center justify-between">
          <div>
            <div className="flex items-center gap-2 text-blue-200 mb-1">
              <GraduationCap className="w-4 h-4" />
              <span className="text-sm font-medium">Student Management</span>
            </div>
            <h1 className="text-2xl font-bold">Manage Students</h1>
            <p className="text-blue-100 text-sm mt-1">{students.length} students registered</p>
          </div>
          <button
            onClick={() => { resetForm(); setShowAddModal(true); }}
            className="bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors backdrop-blur-sm"
          >
            <Plus className="w-4 h-4" />
            Add Student
          </button>
        </div>
      </div>

      {/* Filters */}
      <Card>
        <form onSubmit={handleSearch} className="flex flex-wrap gap-4 items-end">
          <div className="flex-1 min-w-[200px] relative">
            <label className="label">Search Students</label>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-secondary-400" />
              <input
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Search by name or ID..."
                className="input-field pl-10"
              />
            </div>
          </div>
          <div>
            <label className="label">Year Level</label>
            <select
              value={filters.yearLevel}
              onChange={(e) => setFilters(prev => ({ ...prev, yearLevel: e.target.value }))}
              className="input-field w-auto"
            >
              <option value="">All Years</option>
              <option value="1st Year">1st Year</option>
              <option value="2nd Year">2nd Year</option>
              <option value="3rd Year">3rd Year</option>
              <option value="4th Year">4th Year</option>
            </select>
          </div>
          <div>
            <label className="label">Status</label>
            <select
              value={filters.status}
              onChange={(e) => setFilters(prev => ({ ...prev, status: e.target.value }))}
              className="input-field w-auto"
            >
              <option value="">All Status</option>
              <option value="Regular">Regular</option>
              <option value="Irregular">Irregular</option>
              <option value="Drop Out">Drop Out</option>
            </select>
          </div>
          <button type="submit" className="btn-primary">Search</button>
        </form>
      </Card>

      {/* Students Table */}
      <Card>
        {loading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="w-8 h-8 animate-spin text-primary-600" />
          </div>
        ) : students.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="table-modern">
              <thead>
                <tr>
                  <th>Student ID</th>
                  <th>Name</th>
                  <th>Year & Section</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {students.map((student) => (
                  <tr key={student.id}>
                    <td className="font-medium text-primary-600">{student.student_id}</td>
                    <td>
                      <div>
                        <p className="font-medium text-secondary-800">{student.first_name} {student.last_name}</p>
                        <p className="text-xs text-secondary-500">{student.email || 'No email'}</p>
                      </div>
                    </td>
                    <td>{student.year_level} - {student.section}</td>
                    <td>
                      <span className={`badge ${
                        student.status_record === 'Regular' ? 'badge-success' :
                        student.status_record === 'Irregular' ? 'badge-warning' : 'badge-danger'
                      }`}>
                        {student.status_record}
                      </span>
                    </td>
                    <td>
                      <div className="flex items-center gap-1">
                        <button
                          onClick={() => openViewModal(student)}
                          className="p-2 text-secondary-500 hover:text-secondary-700 hover:bg-secondary-100 rounded-lg transition-colors"
                          title="View"
                        >
                          <Eye className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => openEditModal(student)}
                          className="p-2 text-blue-500 hover:text-blue-700 hover:bg-blue-50 rounded-lg transition-colors"
                          title="Edit"
                        >
                          <Edit className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => handleResetPassword(student.id)}
                          className="p-2 text-orange-500 hover:text-orange-700 hover:bg-orange-50 rounded-lg transition-colors"
                          title="Reset Password"
                        >
                          <Key className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => handleDeleteStudent(student.id)}
                          className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors"
                          title="Delete"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state py-16">
            <GraduationCap className="w-12 h-12" />
            <p className="text-base font-medium">No students found</p>
            <p className="text-sm">Try adjusting your search or filters</p>
          </div>
        )}
      </Card>

      {/* Add Student Modal */}
      <Modal
        isOpen={showAddModal}
        onClose={() => setShowAddModal(false)}
        title="Add New Student"
        size="large"
      >
        <form onSubmit={handleAddStudent} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="label">Student ID *</label>
              <input
                type="text"
                value={formData.studentId}
                onChange={(e) => setFormData(prev => ({ ...prev, studentId: e.target.value }))}
                className="input-field"
                required
              />
            </div>
            <div>
              <label className="label">Password *</label>
              <input
                type="password"
                value={formData.password}
                onChange={(e) => setFormData(prev => ({ ...prev, password: e.target.value }))}
                className="input-field"
                required
                minLength={6}
              />
            </div>
            <div>
              <label className="label">First Name *</label>
              <input
                type="text"
                value={formData.firstName}
                onChange={(e) => setFormData(prev => ({ ...prev, firstName: e.target.value }))}
                className="input-field"
                required
              />
            </div>
            <div>
              <label className="label">Last Name *</label>
              <input
                type="text"
                value={formData.lastName}
                onChange={(e) => setFormData(prev => ({ ...prev, lastName: e.target.value }))}
                className="input-field"
                required
              />
            </div>
            <div>
              <label className="label">Year Level</label>
              <select
                value={formData.yearLevel}
                onChange={(e) => setFormData(prev => ({ ...prev, yearLevel: e.target.value }))}
                className="input-field"
              >
                <option value="">Select Year Level</option>
                <option value="1st Year">1st Year</option>
                <option value="2nd Year">2nd Year</option>
                <option value="3rd Year">3rd Year</option>
                <option value="4th Year">4th Year</option>
              </select>
            </div>
            <div>
              <label className="label">Section</label>
              <input
                type="text"
                value={formData.section}
                onChange={(e) => setFormData(prev => ({ ...prev, section: e.target.value }))}
                className="input-field"
              />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button type="button" onClick={() => setShowAddModal(false)} className="btn-secondary flex-1">
              Cancel
            </button>
            <button type="submit" disabled={saving} className="btn-primary flex-1 flex items-center justify-center gap-2">
              {saving && <Loader2 className="w-4 h-4 animate-spin" />}
              {saving ? 'Adding...' : 'Add Student'}
            </button>
          </div>
        </form>
      </Modal>

      {/* Edit Student Modal */}
      <Modal
        isOpen={showEditModal}
        onClose={() => setShowEditModal(false)}
        title="Edit Student"
        size="large"
      >
        <form onSubmit={handleUpdateStudent} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="label">First Name</label>
              <input
                type="text"
                value={formData.firstName}
                onChange={(e) => setFormData(prev => ({ ...prev, firstName: e.target.value }))}
                className="input-field"
              />
            </div>
            <div>
              <label className="label">Last Name</label>
              <input
                type="text"
                value={formData.lastName}
                onChange={(e) => setFormData(prev => ({ ...prev, lastName: e.target.value }))}
                className="input-field"
              />
            </div>
            <div>
              <label className="label">Year Level</label>
              <select
                value={formData.yearLevel}
                onChange={(e) => setFormData(prev => ({ ...prev, yearLevel: e.target.value }))}
                className="input-field"
              >
                <option value="">Select Year Level</option>
                <option value="1st Year">1st Year</option>
                <option value="2nd Year">2nd Year</option>
                <option value="3rd Year">3rd Year</option>
                <option value="4th Year">4th Year</option>
              </select>
            </div>
            <div>
              <label className="label">Section</label>
              <input
                type="text"
                value={formData.section}
                onChange={(e) => setFormData(prev => ({ ...prev, section: e.target.value }))}
                className="input-field"
              />
            </div>
            <div>
              <label className="label">Status</label>
              <select
                value={formData.statusRecord}
                onChange={(e) => setFormData(prev => ({ ...prev, statusRecord: e.target.value }))}
                className="input-field"
              >
                <option value="Regular">Regular</option>
                <option value="Irregular">Irregular</option>
                <option value="Drop Out">Drop Out</option>
              </select>
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button type="button" onClick={() => setShowEditModal(false)} className="btn-secondary flex-1">
              Cancel
            </button>
            <button type="submit" disabled={saving} className="btn-primary flex-1">
              {saving ? 'Updating...' : 'Update Student'}
            </button>
          </div>
        </form>
      </Modal>

      {/* View Student Modal */}
      <Modal
        isOpen={showViewModal}
        onClose={() => setShowViewModal(false)}
        title="Student Details"
        size="large"
      >
        {selectedStudent && (
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-secondary-500">Student ID</p>
                <p className="font-medium">{selectedStudent.student_id}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Full Name</p>
                <p className="font-medium">{selectedStudent.first_name} {selectedStudent.middle_name} {selectedStudent.last_name}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Year & Section</p>
                <p className="font-medium">{selectedStudent.year_level} - {selectedStudent.section}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Status</p>
                <p className="font-medium">{selectedStudent.status_record}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Email</p>
                <p className="font-medium">{selectedStudent.email || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Contact</p>
                <p className="font-medium">{selectedStudent.contact_number || 'N/A'}</p>
              </div>
              <div className="col-span-2">
                <p className="text-sm text-secondary-500">Address</p>
                <p className="font-medium">{selectedStudent.address || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Guardian</p>
                <p className="font-medium">{selectedStudent.guardian_name || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-secondary-500">Guardian Contact</p>
                <p className="font-medium">{selectedStudent.guardian_contact || 'N/A'}</p>
              </div>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default ManageStudents;
